  1	import * as React from 'react';
  2	import { IRow, ISortBy, OnSort, SortByDirection, TableVariant } from '@patternfly/react-table';
  3	import { SimpleTable } from '../Table/SimpleTable';
  4	import {
  5	  EmptyState,
  6	  EmptyStateBody,
  7	  EmptyStateVariant,
  8	  Label,
  9	  Title,
 10	  TitleSizes,
 11	  Tooltip,
 12	  TooltipPosition
 13	} from '@patternfly/react-core';
 14	import { kialiStyle } from '../../styles/StyleUtils';
 15	import { t } from 'i18next';
 16	import { SortableCompareTh } from './ZtunnelConfig';
 17	import { WaypointInfo, WorkloadInfo } from '../../types/Workload';
 18	import { isMultiCluster } from '../../config';
 19	import { Link } from 'react-router-dom-v5-compat';
 20	import { PFBadge, PFBadges } from '../Pf/PfBadges';
 21	import { WaypointType } from '../../types/Ambient';
 22	import { KialiIcon } from '../../config/KialiIcon';
 23	import { infoStyle } from '../../styles/IconStyle';
 24	
 25	type WaypointWorkloadsProps = {
 26	  type: string;
 27	  workloads: WaypointInfo[];
 28	};
 29	
 30	const emptyStyle = kialiStyle({
 31	  padding: 0,
 32	  margin: 0
 33	});
 34	
 35	const iconStyle = kialiStyle({
 36	  margin: 0,
 37	  padding: 0,
 38	  display: 'inline-block'
 39	});
 40	
 41	const itemStyle = kialiStyle({
 42	  paddingBottom: '0.25rem',
 43	  listStyle: 'none'
 44	});
 45	
 46	const labeledBy = (
 47	  <Tooltip
 48	    key="tooltip_waypoint_workloads"
 49	    position={TooltipPosition.right}
 50	    content={
 51	      <div style={{ textAlign: 'left' }}>
 52	        <div>
 53	          Indicates workloads/services with the <Label>istio.io/use-waypoint</Label> label for this waypoint. The
 54	          'Labeled by' column indicates the source of the label—whether it comes from the namespace, service, or
 55	          workload. In cases where multiple labels exist, it shows which one takes precedence.
 56	        </div>
 57	      </div>
 58	    }
 59	  >
 60	    <>
 61	      <KialiIcon.Info className={infoStyle} />
 62	    </>
 63	  </Tooltip>
 64	);
 65	
 66	const columns: SortableCompareTh<WorkloadInfo>[] = [
 67	  {
 68	    title: t('Name'),
 69	    sortable: true,
 70	    compare: (a, b) => a.name.localeCompare(b.name)
 71	  },
 72	  {
 73	    title: t('Namespace'),
 74	    sortable: true,
 75	    compare: (a, b) => a.namespace.localeCompare(b.namespace)
 76	  },
 77	  {
 78	    title: t('Labeled by'),
 79	    sortable: false
 80	  }
 81	];
 82	
 83	export const WaypointWorkloadsTable: React.FC<WaypointWorkloadsProps> = (props: WaypointWorkloadsProps) => {
 84	  const [sortBy, setSortBy] = React.useState(0);
 85	  const [sortDirection, setSortDirection] = React.useState(SortByDirection.asc);
 86	
 87	  const compare = columns[sortBy].compare;
 88	  const sorted = compare
 89	    ? props.workloads?.sort(sortDirection === SortByDirection.asc ? compare : (a, b) => compare(b, a))
 90	    : props.workloads;
 91	
 92	  const renderItem = (namespace, name, type: string, cluster?: string): React.ReactNode => {
 93	    let href = `/namespaces/${namespace}/${type}s/${name}`;
 94	
 95	    if (cluster && isMultiCluster) {
 96	      href = `${href}?clusterName=${cluster}`;
 97	    }
 98	
 99	    const link = <Link to={href}>{name}</Link>;
100	
101	    const badgeType = type === WaypointType.Service ? PFBadges.Service : PFBadges.Workload;
102	    return (
103	      <li key={`${type}_${name}`} className={itemStyle}>
104	        <div className={iconStyle}>
105	          <PFBadge badge={badgeType} position={TooltipPosition.top} />
106	        </div>
107	
108	        <span>{link}</span>
109	      </li>
110	    );
111	  };
112	
113	  const rows: IRow[] = sorted
114	    ? sorted.map(element => {
115	        return {
116	          cells: [
117	            renderItem(element.namespace, element.name, props.type, element.cluster),
118	            element.namespace,
119	            element.labelType
120	          ]
121	        };
122	      })
123	    : [];
124	
125	  const sort: ISortBy = { index: sortBy, direction: sortDirection };
126	  const onSort: OnSort = (_event: React.MouseEvent, index: number, sortDirection: SortByDirection) => {
127	    setSortBy(index);
128	    setSortDirection(sortDirection);
129	  };
130	
131	  const noWorkloads: React.ReactNode = (
132	    <EmptyState variant={EmptyStateVariant.sm} className={emptyStyle}>
133	      <EmptyStateBody className={emptyStyle} data-test="istio-config-empty">
134	        {props.type === WaypointType.Service ? t('No enrolled services found') : t('No enrolled workloads found')}
135	      </EmptyStateBody>
136	    </EmptyState>
137	  );
138	
139	  return (
140	    <>
141	      <div>
142	        <Title headingLevel="h5" size={TitleSizes.lg} data-test="enrolled-data-title">
143	          {t('List of enrolled')} {props.type}s {labeledBy}
144	        </Title>
145	      </div>
146	      <SimpleTable
147	        label={`${props.type} ${t('config')}`}
148	        columns={columns}
149	        rows={rows}
150	        variant={TableVariant.compact}
151	        emptyState={noWorkloads}
152	        sortBy={sort}
153	        onSort={onSort}
154	      />
155	    </>
156	  );
157	};

